code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let genome;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        genome = input;
        console.log(genome);
        rl.close();
    }
});
